// 2.7.101 | 2022-01-03 | raj  | STRY0116242 - Certification Fixes - Dot Walking to sys_id
// Script Continued Below
var Tasker_GenerateTaskFromTemplate = Class.create();
Tasker_GenerateTaskFromTemplate.prototype = {
    initialize: function() {
		gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - initialize');
		// STRY0110317 
		this.tdc = new TaskerDurationCalculator();
    },

// DFCT0012181 - remove the synchronous option from this method.
//               If we kick off the template using a business rule, we can't do it through an Async rule
//               Async rule holds a thread.  This update will force a business rule start of a template to always run it through an event.
