// 		// if the current template is run from a daily schedule, or the template was requested to be run asynchronously
// 		// or the maximum concurrent templates has been exceeded, then use event to queue run
// 		//if(grTemplateInstance.u_status == 'queued' || (maximumRunningTemplates > 0 && runningTemplates > maximumRunningTemplates)){
// 		//	// Queue Template
// 		//	grTemplateInstance.u_status = 'queued';
// 		//	grTemplateInstance.update();
// 			gs.eventQueue('x_153465_discovert.Start_Template', grTemplateInstance, grTemplateInstance.originator);
// 		//} else {
