	startTemplate: function(recTempInstance){
		try {
			recTempInstance.u_status = 'initialized';
			recTempInstance.update();
			// STRY0110317
			var startTime = new GlideDateTime();
			var longestEndTime = new GlideDateTime();

			var recTaskInst = this.initiateTemplate(recTempInstance, startTime, longestEndTime);

			this.buildTemplateTask(recTaskInst, recTempInstance, startTime, longestEndTime);
			recTempInstance.u_status = 'completed';
			recTempInstance.update();
		} catch(e) {
			recTempInstance.u_status = 'error';
			recTempInstance.u_error_message = 'Tasker Error in (startTemplate) - ' + e.toString();
			recTempInstance.update();

			gs.error(e);
		}

	},

	initiateTemplate: function(recTempInstance, startTime, longestEndTime){
		try {
			// do not run template if the template or the top template task are inactive.
			// routing_template_ref.u_active=true^routing_template_ref.parent_task_def.active=true^EQ

			// STRY0047782
			var recProcessDef = new GlideRecord('x_153465_discovert_discover_routing_template');
			// STRY0090463
			if (recProcessDef.get(recTempInstance.getValue('routing_template_ref'))) {
				// STRY0085827
				if (recProcessDef.u_active == false) {
					// Template is not active, exit and close workflow
					return;
				}

				// STRY0100724
				recTempInstance.u_status = 'in_progress';
				recTempInstance.update();


				var recTaskInst = new GlideRecord('x_153465_discovert_route_task_instance');
				// RAJ - STRY0014064 When a template is run by a task 
				// If the user is given the option to make the task where the template was started as the "top Task" 
				// then this task would not be created, an if logic would look up that checkbox
				// if the user chooses not to add the "middle" task, all of the lines between the comment block would go in the if
				// ---------------------------------------------------------------------------------------------
				// - start of IF block
				// - if there is a parent task on the instance and the user checks the box above, 
				// - then instead of initialize below GET the Task associated with teh Parent_Task provided
				// ---------------------------------------------------------------------------------------------
				recTaskInst.initialize();
				// STRY0014064 - if the template was started under a task, then the parent_task field will be populated.  
				//  Add this new record to the tree
				if (recTempInstance.parent_task + '' != '') {
					recTaskInst.parent = recTempInstance.parent_task;
					// DFCT0012389 - DFCT0012390
					recTaskInst.u_privacy = recTempInstance.parent_task.u_privacy;
				} else {
					// DFCT0012389 - DFCT0012390
					recTaskInst.u_privacy = recTempInstance.u_privacy;
				}
				// ---------------------------------------------------------------------------------------------
				// - end of future IF block
				// ---------------------------------------------------------------------------------------------

				// RAJ - 2018-02-20 STRY0010829 - Short Desc and Instructions are missing in the Top Task . They need to be copied from the Process Definition.
				// had to change the line below to recTempInstance.sys_id from recRunTemp.sys_id.
				// The tasker instance insert is expecting the proces definition, not the process instance.

				// RAJ - STRY 0011909 - modify process template
				// the child route was left in here, but is only used to show what process is being run.
				//This is currently only set on the top tasker, not an any children
				recTaskInst.u_parent_template = recTempInstance.routing_template_ref;
				recTaskInst.source_definition = recProcessDef.getValue('parent_task_def');
				// STRY0063859 - This is needed to pass values into the top task from the Template Instance for or the API
				recTaskInst.tasker_process_instance = recTempInstance.sys_id;

				// RAJ Originator
				if (recTempInstance.u_schedule_originator != '' && recTempInstance.u_schedule_originator != undefined) {
					recTaskInst.originator = recTempInstance.u_schedule_originator;
					recTaskInst.u_task_requester = recTempInstance.u_schedule_originator;
				} else {
					recTaskInst.originator = recTempInstance.originator;
					recTaskInst.u_task_requester = recTempInstance.originator;
				}

				// STRY0105125
				if (recTempInstance.getValue('u_create_tasks_in_draft_state')==true){
					// Set the Task state to Draft
					recTaskInst.state = -6;
				}

				// STRY0090463 - moved this out of the if block to use again later
				var gdt = new GlideDateTime();
				if (recTempInstance.instance_notation == '' || recTempInstance.instance_notation == undefined) {
					var currentTime = gdt.getDisplayValue();
					recTaskInst.instance_notation = currentTime;
				} else {
					recTaskInst.instance_notation = recTempInstance.instance_notation;
					recTaskInst.u_objective = recTempInstance.u_objective;
				}
				// STRY0090463
				var recTopTempTask = new GlideRecord('x_153465_discovert_route_tasks');
				// STRY0090463
				if (recTopTempTask.get(recProcessDef.getValue('parent_task_def'))) {
					// STRY0110317
					this._setTaskDates(recTopTempTask, recTaskInst, startTime, longestEndTime);
				}

				recTaskInst.insert();

				// STRY0014064 Set the Top Task on the Process Instance
				recTempInstance.u_top_task = recTaskInst.sys_id;
				recTempInstance.update();
			}
			return recTaskInst;
		} catch(e) {
			recTempInstance.u_status = 'error';
			recTempInstance.u_error_message = 'Tasker Error in (initiateTemplate) - ' + e.toString();
			recTempInstance.update();
			gs.error(e);
		}

	},

	buildTemplateTask: function(recTaskInst, recTempInstance, startTime, longestEndTime) {
		try{
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - buildTemplateTask start');

			var oTaskInstance = {};
			oTaskInstance.recTaskInst = recTaskInst;
			oTaskInstance.u_total_Tasks = 0;
			oTaskInstance.u_Tasks_loaded_count = 0;
			oTaskInstance.u_Task_route_order_count = 0;
			oTaskInstance.u_current_duration_offset = 0;
			oTaskInstance.startTime = new GlideDateTime(startTime);
			// when this returns, it will have set the longestEndTime to the end time of the top Task
			// The longest end time needs to be reset at each level down the tree as it only moves forward when a new order for a level is hit
			// this way, all items whose parents have the same order will start at the same time
			oTaskInstance.longestEndTime = new GlideDateTime(startTime);

			this.loadTemplateTask(oTaskInstance);
			while (oTaskInstance.u_Tasks_loaded_count < oTaskInstance.u_total_Tasks) {
				// createTasksForOrderOnTemplateTask creates all of the tasks for a single order on the template task
				this.createTasksForOrderOnTemplateTask(oTaskInstance, recTempInstance);

			}
			// once the level is complete, set the end time passed out to be the end time of the level

			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - buildTemplateTask end');
		} catch(e) {
			recTempInstance.u_status = 'error';
			recTempInstance.u_error_message = 'Tasker Error in (buildTemplateTask) - ' + e.toString();
			recTempInstance.update();
			gs.error(e);
		}

	},

	loadTemplateTask: function(oTaskInstance){		
		try{
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - loadTemplateTask start');
			var taskDefQ = new GlideAggregate('x_153465_discovert_route_tasks');
			taskDefQ.addQuery('parent', oTaskInstance.recTaskInst.source_definition);
			// STRY0085827 - do not run task templates that were deactivated
			taskDefQ.addQuery('active', true);

			taskDefQ.addAggregate('COUNT');
			taskDefQ.query();
			if (taskDefQ.next()){
				oTaskInstance.u_total_Tasks = taskDefQ.getAggregate('COUNT');
			}
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - loadTemplateTask - oTaskInstance.u_total_Tasks: ' + oTaskInstance.u_total_Tasks);
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - loadTemplateTask end');
		} catch(e) {
			recTempInstance.u_status = 'error';
			recTempInstance.u_error_message = 'Tasker Error in (loadTemplateTask) - ' + e.toString();
			recTempInstance.update();
			gs.error(e);
		}
	},	

	createTasksForOrderOnTemplateTask: function(oTaskInstance, recTempInstance){
		try{
			var startTime = new GlideDateTime(oTaskInstance.startTime);
			var longestEndTime = new GlideDateTime(oTaskInstance.longestEndTime);
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - createTasksForOrderOnTemplateTask start');

			oTaskInstance.u_Task_route_order_count +=1;
			// we query to get the list of all Task Defs in this "route order"
			// the loop below will process each Task Defs in this route order
			// it will increment the total Task Defs processed for each order
			var taskDefQ = new GlideRecord('x_153465_discovert_route_tasks');
			taskDefQ.addQuery('parent',oTaskInstance.recTaskInst.source_definition);
			// if this is the fisrt pass, the route order is 1 b/c it started at 0
			// the order default is 1.  there should be nothing that is 0 
			if (oTaskInstance.u_Task_route_order_count>0){
				taskDefQ.addQuery('route_order',oTaskInstance.u_Task_route_order_count);
			}
			// STRY0085827 - do not run task templates that were deactivated
			taskDefQ.addQuery('active', true);
			taskDefQ.query();

			while (taskDefQ.next()){
				var recTaskInst = new GlideRecord('x_153465_discovert_route_task_instance');
				recTaskInst.initialize();
				//  this is the relationship to the route instance
				recTaskInst.source_definition = taskDefQ.sys_id;
				recTaskInst.parent = oTaskInstance.recTaskInst.sys_id;
				// STRY0162001
				recTaskInst.u_privacy = oTaskInstance.recTaskInst.u_privacy;

				recTaskInst.u_task_requester = oTaskInstance.recTaskInst.parent.originator;

				// STRY0110317
				this._setTaskDates(taskDefQ, recTaskInst, startTime, longestEndTime);

				// STRY0116242 - Certification Fixes - Dot Walking to sys_id				
				recTaskInst.tasker_process_instance = oTaskInstance.recTaskInst.getValue("tasker_process_instance");
				recTaskInst.source_definition = taskDefQ.sys_id;
				// NOTE: TODO: set number to parent number here...
				recTaskInst.insert();

				// buildTemplateTask is called again to initiate the next level down the Template Tree
				var nextLevel =  new Tasker_GenerateTaskFromTemplate();
				// set to current task instance's start time and end time to its children, NOTE, the end time gets reset to the start time in the next level
				var nextLevelStart = new GlideDateTime(oTaskInstance.startTime);
				var nextLevelLongestEndTime = new GlideDateTime(oTaskInstance.longestEndTime);
				nextLevel.buildTemplateTask(recTaskInst, recTempInstance, nextLevelStart, nextLevelLongestEndTime);

				// increment the total routes processed for each route in this order
				oTaskInstance.u_Tasks_loaded_count +=1;
			}
			oTaskInstance.longestEndTime = new GlideDateTime(longestEndTime);
			// the order is complete, move start time to end time
			oTaskInstance.startTime = new GlideDateTime(oTaskInstance.longestEndTime);
			gs.debug('x_153465_discovert.Tasker_GenerateTaskFromTemplate - createTasksForOrderOnTemplateTask end');
		} catch(e) {
			recTempInstance.u_status = 'error';
			recTempInstance.u_error_message = 'Tasker Error in (createTasksForOrderOnTemplateTask) - ' + e.toString();
			recTempInstance.update();
			gs.error(e);
		}

	},

	// grTempTask              - GlideRecord       - Template Task 
	// grTask                  - GlideRecord       - Template Task 
	// startTime               - GlideDateTime     - Start time, this is updated in this method
	// longestEndTime          - GlideDateTime     - Current Latest end time for the Order, updated in this method
	_setTaskDates: function(grTempTask, grTask, startTime, longestEndTime){
		var gdt_start = new GlideDateTime();
		gdt_start.setGlideDateTime(startTime);
		// set the start time
		grTask.setValue('expected_start', gdt_start.getValue());

		var gdt = new GlideDateTime();
		gdt.setGlideDateTime(startTime);

		if(grTempTask.u_duration_days>0){
			gdt = this.tdc.calculateDateOfAddedBusinessDays(grTempTask, grTempTask.u_duration_days, gdt);
		} else {  // if duration = 0, we need to move to the next day in the order to prevent all tasks in multiple orders from being due on the same day
			gdt = this.tdc.checkStartTime(grTempTask, gdt);
		}

		// add the due time to the start time
		if(grTempTask.u_duration_time_due){
			var gdTimeDue = new GlideDuration();
			gdTimeDue.setValue(grTempTask.u_duration_time_due);
			var durMS = this.tdc.getDurationlMS(gdTimeDue);

			var gDateEnd = new GlideDate();
			gDateEnd.setDisplayValue(gdt.getDisplayValue());
			var gTimeDue = new GlideTime();
			var gdtDue = new GlideDateTime();
			gTimeDue.setDisplayValue("00:00:00");
			var dueTime = gTimeDue.getDisplayValue();
			gdtDue.setDisplayValue(gDateEnd.getDisplayValue() + " " + dueTime);

			// DFCT0010609 - Time field has no date so, the date is assumged to be 1/1/1970
			//               if current date is in daylihgt savings time, then add an hour to make it up
			var offset = gdtDue.getDSTOffset();   
			if (offset > 0) {
				durMS = durMS - 3600;
			}
			gdtDue.addSeconds(durMS/1000);
			gdt = gdtDue;

		} else {
			// set to eand of day
			gdt = this.tdc.calculateEndOfDay (grTempTask, gdt);
		}
		if(gdt.getNumericValue() > longestEndTime.getNumericValue()){
			longestEndTime.setGlideDateTime(gdt);
		}
		// STRY0098078
		grTask.setValue("suspense_date", gdt.getValue());
		grTask.setValue("due_date", gdt.getValue());
	},

	// NOTE: this function should go in a utility class.  The same function exists in TaskerScheduleScript
	padStart : function(input, character, len) {
		var output = input + "";
		while (output.length < len){
			output = character + output;
		}
		return output;
	},

    type: 'Tasker_GenerateTaskFromTemplate'
};
